public int minDifference(int[] nums) {
    int n = nums.length;
    if (n <= 4) return 0;
    Arrays.sort(nums);
    int res = Integer.MAX_VALUE;
    for (int i = 0; i <= 3; ++i)
        res = Math.min(res, nums[n - 4 + i] - nums[i]);
    return res;
}
